34	    if (version) {
35	      acc[version.toString()] =
36	        version === item.data?.latestVersion?.version
37	          ? t('{{version}} (latest)', { version })
38	          : version;
39	    }
40	    return acc;
41	  }, {});
42	
43	  const toggle = (toggleRef: React.Ref<MenuToggleElement>) => (
44	    <MenuToggle
45	      className="opp-quick-search-details__version-dropdown"
46	      onClick={toggleIsOpen}
47	      isExpanded={isOpen}
48	      ref={toggleRef}
49	      isDisabled={versions.length === 1}
50	      data-test="task-version"
51	    >
52	      {versionItems[selectedVersion]}
53	    </MenuToggle>
54	  );
