61	        if (value) {
62	          onChange(value);
63	        }
64	        setOpen(false);
65	      }}
66	      toggle={toggle}
67	      onOpenChange={(open) => setOpen(open)}
68	    >
69	      <SelectList>
70	        {Object.keys(versionItems).map((key) => (
71	          <SelectOption key={key} label={versionItems[key]} value={key}>
72	            <div className="opp-quick-search-details__version-dropdown-item">
73	              {versionItems[key]}
